const query = items[0]?.json?.query || items[0]?.json || {};
const expectedToken = $env.INSTAGRAM_DIRECTS_VERIFY_TOKEN || 'fga_directs_2026';
const mode = query['hub.mode'];
const token = query['hub.verify_token'];
const challenge = query['hub.challenge'];

if (mode !== 'subscribe' || token !== expectedToken || !challenge) {
  throw new Error('Falha na verificacao do webhook Meta. Confira o Verify Token.');
}

return [{ json: { challenge: String(challenge) } }];

function text(value) {
  return String(value || '').trim();
}

function lower(value) {
  return text(value).toLowerCase();
}

function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && text(value) !== '') return value;
  }
  return null;
}

function isRiskText(value) {
  const content = lower(value);
  return /(erro|falha|problema|bug|reclama[cç][aã]o|ruim|incomplet|pl[aá]gio|indevid|link errado|valor errado|pre[cç]o errado|n[aã]o funciona|reembolso|chargeback|cobran[cç]a|devolu[cç][aã]o|cancelar|cancelamento)/.test(content);
}

function isCommercialText(value) {
  const content = lower(value);
  return /(valor|pre[cç]o|matr[ií]cula|inscri[cç][aã]o|link|comprar|compra|pagamento|boleto|pix|cart[aã]o|agenda|consulta|palestra|or[cç]amento|quero|interesse|como funciona|curso|forma[cç][aã]o)/.test(content);
}

function topicFor(value) {
  const content = lower(value);
  if (isRiskText(content)) return 'Risco / Reclamacao';
  if (/(jiu|jitsu|kimono|luta|tatame|faixa)/.test(content)) return 'Jiu Jitsu';
  if (/(fam[ií]lia|filh|m[aã]e|pai|marido|espos|casa|crian[cç]a)/.test(content)) return 'Familia';
  if (/(curso|forma[cç][aã]o|aasi|imers[aã]o|mentoria|aula|alun)/.test(content)) return 'Curso / Formacao';
  if (/(consulta|cl[ií]nica|paciente|audiometria|zumbido|aparelho|audiologia|fono)/.test(content)) return 'Consulta / Clinica';
  if (isCommercialText(content)) return 'Interesse comercial';
  return 'Sem tema definido';
}

function potentialFor(value) {
  if (isRiskText(value)) return 'alto';
  if (isCommercialText(value)) return 'alto';
  if (text(value)) return 'medio';
  return 'nao_classificado';
}

function actionFor(value) {
  if (isRiskText(value)) return 'Priorizar resposta humana, corrigir link/valor se aplicavel e registrar acao tomada.';
  if (isCommercialText(value)) return 'Responder com orientacao objetiva, link correto e proximo passo de compra ou atendimento.';
  return 'Responder ou marcar como analisado apos avaliar o contexto da conversa.';
}

function eventTime(event) {
  if (event.timestamp) return new Date(Number(event.timestamp)).toISOString();
  return new Date().toISOString();
}

const body = items[0]?.json?.body || items[0]?.json || {};
const entries = Array.isArray(body.entry) ? body.entry : [];
const rows = [];

for (const entry of entries) {
  const messaging = Array.isArray(entry.messaging) ? entry.messaging : [];

  for (const event of messaging) {
    const message = event.message || {};
    const textMessage = firstValue(
      message.text,
      event.postback?.title,
      message.attachments?.length ? '[Anexo recebido]' : null,
      message.sticker_id ? '[Figurinha recebida]' : null,
      ''
    );

    const senderId = firstValue(event.sender?.id, message.from?.id);
    const recipientId = firstValue(event.recipient?.id);
    const externalId = firstValue(message.mid, event.message?.mid, event.id, `${senderId}-${event.timestamp || Date.now()}`);

    if (!senderId || !externalId) continue;

    rows.push({
      tenant_name: firstValue($env.PLATAFORMA_TENANT_NAME, 'Juliana Coutinho'),
      account_name: firstValue($env.INSTAGRAM_ACCOUNT_NAME, 'Juliana Coutinho'),
      username: firstValue($env.INSTAGRAM_USERNAME, 'fga.jucoutinho'),
      source: 'direct',
      marketing_type: 'interacao_marketing',
      external_id: externalId,
      profile_username: senderId,
      profile_name: firstValue(event.sender?.name, senderId),
      message_text: textMessage,
      media_id: firstValue(event.thread_id, recipientId),
      post_id: null,
      post_permalink: null,
      interaction_at: eventTime(event),
      status: 'novo',
      potential: potentialFor(textMessage),
      product_topic: topicFor(textMessage),
      next_action: actionFor(textMessage),
      origem: 'n8n_instagram_directs_webhook',
      raw_payload: {
        source: 'instagram_webhook',
        entry_id: entry.id,
        sender_id: senderId,
        recipient_id: recipientId,
        event
      }
    });
  }
}

if (!rows.length) {
  return [{ json: { rows: [], skipped: true, reason: 'Webhook recebido, mas sem mensagem de Direct importavel.' } }];
}

return [{ json: { rows, count: rows.length } }];
